1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("block (2x2 square) is a still life", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
19	  });
20	  it("blinker rotates from vertical to horizontal", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(vertical);
23	    expect(result).toHaveLength(3);
24	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
25	  });
26	  it("live cell with more than 3 neighbors dies (overpopulation)", () => {
27	    const gen0: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]];
28	    const result = nextGeneration(gen0);
29	    expect(result).toHaveLength(6);
30	    expect(result).toEqual(expect.arrayContaining([[0, 0], [2, 0], [0, 1], [2, 1], [0, 2], [2, 2]]));
31	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
32	  });
33	  it.todo("dead cell with exactly 3 neighbors becomes alive (reproduction)");
34	  it.todo("supports negative coordinates");
35	});
