1	type Cell = [x: number, y: number];
2	type CellKey = string;
3	
4	const toKey = (x: number, y: number): CellKey => `${x},${y}`;
5	const fromKey = (key: CellKey): Cell => {
6	  const [x, y] = key.split(",");
7	  return [Number(x), Number(y)];
8	};
9	
10	export function nextGeneration(cells: Cell[]): Cell[] {
11	  const liveCells = new Set(cells.map(([x, y]) => toKey(x, y)));
12	  const neighborCounts = new Map<CellKey, number>();
13	  for (const [x, y] of cells) {
14	    for (let dx = -1; dx <= 1; dx++) {
15	      for (let dy = -1; dy <= 1; dy++) {
16	        if (dx === 0 && dy === 0) continue;
17	        const neighborKey = toKey(x + dx, y + dy);
18	        neighborCounts.set(neighborKey, (neighborCounts.get(neighborKey) ?? 0) + 1);
19	      }
20	    }
21	  }
22	  const result: Cell[] = [];
23	  for (const [cellKey, neighborCount] of neighborCounts) {
24	    const survives = neighborCount === 3 || (neighborCount === 2 && liveCells.has(cellKey));
25	    if (survives) {
26	      result.push(fromKey(cellKey));
27	    }
28	  }
29	  return result;
30	}
